let bx = 80, by = 60;
let vx = 1.5, vy = 1.2;
let sx = 1.0, sy = 1.0;
let vsx = 0, vsy = 0;
let br = 35;
const stiffness = 0.15;
const damping = 0.75;

p.setup = function() {
  p.createCanvas(160, 120);
  p.noStroke();
  p.background(0);
};

p.draw = function() {
  let ref = p.getRefImage();
  if (!ref) {
    p.background(0);
    p.fill(150);
    p.textAlign(p.CENTER, p.CENTER);
    p.textSize(9);
    p.text('connect an image \u2192', 80, 60);
    return;
  }
  ref.loadPixels();

  let speedStr = p.getSynthVar('blob_speed') || 'casual';
  let sizeStr = p.getSynthVar('blob_size') || 'medium';
  let squishStr = p.getSynthVar('squishiness') || 'jello';
  let wiggleStr = p.getSynthVar('wiggle_amount') || 'wobbly';
  let bgStr = p.getSynthVar('background_style') || 'black';

  let speedMap = { 'lethargic': 0.8, 'casual': 1.8, 'brisk': 3.5, 'hyper': 6.0 };
  let sizeMap = { 'tiny': 15, 'small': 25, 'medium': 35, 'large': 50, 'massive': 70 };
  let squishMap = { 'rigid': 0.0, 'bouncy': 0.25, 'jello': 0.5, 'pancake': 0.85 };
  let wiggleMap = { 'none': 0, 'slight': 3, 'wobbly': 8, 'turbulent': 15 };
  let bgMap = {
    'black': {c: 0, a: 255},
    'white': {c: 255, a: 255},
    'trails': {c: 0, a: 40},
    'smear': {c: 0, a: 12}
  };

  let targetSpeed = speedMap[speedStr];
  let targetBr = sizeMap[sizeStr];
  let squishAmt = squishMap[squishStr];
  let wiggleIntensity = wiggleMap[wiggleStr];
  let bg = bgMap[bgStr];

  p.fill(bg.c, bg.a);
  p.rect(0, 0, 160, 120);

  br += (targetBr - br) * 0.1;

  let mag = p.sqrt(vx * vx + vy * vy);
  if (mag > 0.0001) {
    vx = (vx / mag) * targetSpeed;
    vy = (vy / mag) * targetSpeed;
  } else {
    vx = targetSpeed; vy = 0;
  }

  bx += vx;
  by += vy;

  let hitX = false, hitY = false;
  if (bx - br < 0) { bx = br; vx = p.abs(vx); hitX = true; }
  else if (bx + br > 160) { bx = 160 - br; vx = -p.abs(vx); hitX = true; }

  if (by - br < 0) { by = br; vy = p.abs(vy); hitY = true; }
  else if (by + br > 120) { by = 120 - br; vy = -p.abs(vy); hitY = true; }

  if (hitX || hitY) {
    let angle = p.atan2(vy, vx) + p.random(-0.15, 0.15);
    vx = p.cos(angle) * mag;
    vy = p.sin(angle) * mag;
  }

  if (hitX) { sx = 1.0 - squishAmt; sy = 1.0 + squishAmt; }
  if (hitY) { sx = 1.0 + squishAmt; sy = 1.0 - squishAmt; }

  let fx = (1.0 - sx) * stiffness;
  vsx = (vsx + fx) * damping;
  sx += vsx;

  let fy = (1.0 - sy) * stiffness;
  vsy = (vsy + fy) * damping;
  sy += vsy;

  p.push();
  p.translate(bx, by);
  p.scale(sx, sy);

  p.drawingContext.save();
  p.drawingContext.beginPath();
  let pts = 40;
  let wBase = p.millis() * 0.002;
  for (let i = 0; i < pts; i++) {
    let angle = p.map(i, 0, pts, 0, p.TWO_PI);
    let n = p.noise(p.cos(angle) + 1, p.sin(angle) + 1, wBase);
    let r = br + p.map(n, 0, 1, -wiggleIntensity, wiggleIntensity);
    let x = r * p.cos(angle);
    let y = r * p.sin(angle);
    if (i === 0) p.drawingContext.moveTo(x, y);
    else p.drawingContext.lineTo(x, y);
  }
  p.drawingContext.closePath();
  p.drawingContext.clip();

  p.imageMode(p.CENTER);
  let pad = wiggleIntensity;
  p.image(ref, 0, 0, (br + pad) * 2.66, (br + pad) * 2);

  p.drawingContext.restore();
  p.pop();
};
